201	  modelId?: string;
202	  lensMode?: LensMode;
203	  elementsById: Record<string, Element>;
204	  onUpsertSemantic?: (cmd: Record<string, unknown>) => void;
205	}) {
206	  const { sheet: sh, evidenceFullBleed, modelId, lensMode, elementsById } = props;
207	
208	  const bleed = evidenceFullBleed ?? false;
209	  const { widthMm: wMm, heightMm: hMm } = normalizeSheetPaperMm(sh.paperWidthMm, sh.paperHeightMm);
210	
211	  const vps = (sh.viewportsMm ?? []) as Array<Record<string, unknown>>;
212	  const nextDraftBase = (): SheetViewportMmDraft[] =>
213	    vps.map((vp, i) => normalizeViewportRaw(vp, i));
214	  const [vpDrafts, setVpDrafts] = useState<SheetViewportMmDraft[]>(() => nextDraftBase());
215	
216	  const [tbDraft, setTbDraft] = useState(() => normalizeTitleblockDraftFromSheet(sh));
217	
218	  const svgRef = useRef<SVGSVGElement | null>(null);
219	  const dragRef = useRef<{ index: number; grabDX: number; grabDY: number } | null>(null);
220	  const resizeRef = useRef<{ index: number } | null>(null);
221	
222	  const [isExportingPdf, setIsExportingPdf] = useState(false);
223	
224	  const handleExportPdf = useCallback(async () => {
225	    const el = svgRef.current;
226	    if (!el || isExportingPdf) return;
227	    setIsExportingPdf(true);
228	    try {
229	      const safeFilename = (sh.name || 'sheet').replace(/[^a-zA-Z0-9_-]/g, '_');
230	      await exportSheetToPdf(el, { paperSize: 'A4', filename: `${safeFilename}.pdf` });
231	    } finally {
232	      setIsExportingPdf(false);
233	    }
234	  }, [sh.name, isExportingPdf]);
235	
236	  const authoring = Boolean(props.onUpsertSemantic);
237	
238	  const tp = sh.titleblockParameters ?? {};
239	  const sheetNo = tp.sheetNumber ?? tp.sheetNo ?? '';
240	  const revision = tp.revision ?? '';
241	  const project = tp.projectName ?? tp.project ?? '';
242	  const drawn = tp.drawnBy ?? '';
243	  const chk = tp.checkedBy ?? '';
244	  const issued = tp.issueDate ?? tp.date ?? '';
245	
246	  const hdrParts: string[] = [];
247	  if (String(sheetNo).trim()) hdrParts.push(String(sheetNo).trim());
248	  if (String(revision).trim()) hdrParts.push(`Rev ${String(revision).trim()}`);
249	  const hdr = hdrParts.join(' · ');
250	
251	  const footerLines: string[] = [];
252	  if (hdr) footerLines.push(hdr);
253	  if (String(project).trim()) footerLines.push(String(project).trim());
254	  if (String(drawn).trim() || String(chk).trim()) {
255	    footerLines.push(
256	      `Drn ${String(drawn).trim()} · Chk ${String(chk).trim()}`.replace(/\s*·\s*$/, '').trim(),
257	    );
258	  }
259	  if (String(issued).trim()) footerLines.push(String(issued).trim());
