54	/**
55	 * Renders a simplified floor-plan thumbnail as SVG JSX inside a viewport frame.
56	 * Returns null when no geometry is available for the given plan view.
57	 */
58	function renderPlanThumbnail(
59	  elementsById: Record<string, Element>,
60	  planViewId: string,
61	  widthMm: number,
62	  heightMm: number,
63	): ReactElement | null {
64	  const planView = elementsById[planViewId];
65	  if (!planView || planView.kind !== 'plan_view') return null;
66	
67	  const levelId = planView.levelId;
68	
69	  const walls = Object.values(elementsById).filter(
70	    (el): el is Extract<Element, { kind: 'wall' }> => el.kind === 'wall' && el.levelId === levelId,
71	  );
72	  const rooms = Object.values(elementsById).filter(
73	    (el): el is Extract<Element, { kind: 'room' }> => el.kind === 'room' && el.levelId === levelId,
74	  );
75	  const floors = Object.values(elementsById).filter(
76	    (el): el is Extract<Element, { kind: 'floor' }> =>
77	      el.kind === 'floor' && el.levelId === levelId,
78	  );
79	
80	  if (walls.length === 0 && rooms.length === 0 && floors.length === 0) return null;
81	
82	  // Collect all world coordinate points to compute bounding box
83	  const allPoints: XY[] = [];
84	  for (const w of walls) {
85	    allPoints.push(w.start, w.end);
86	  }
87	  for (const r of rooms) {
88	    allPoints.push(...r.outlineMm);
89	  }
90	  for (const f of floors) {
91	    allPoints.push(...f.boundaryMm);
92	  }
93	
94	  if (allPoints.length === 0) return null;
95	
96	  let bbMinX = allPoints[0].xMm;
97	  let bbMaxX = allPoints[0].xMm;
98	  let bbMinY = allPoints[0].yMm;
99	  let bbMaxY = allPoints[0].yMm;
100	  for (const pt of allPoints) {
101	    if (pt.xMm < bbMinX) bbMinX = pt.xMm;
102	    if (pt.xMm > bbMaxX) bbMaxX = pt.xMm;
103	    if (pt.yMm < bbMinY) bbMinY = pt.yMm;
104	    if (pt.yMm > bbMaxY) bbMaxY = pt.yMm;
105	  }
106	
107	  // 5% padding
108	  const bbW = bbMaxX - bbMinX;
109	  const bbH = bbMaxY - bbMinY;
110	  const padX = bbW * 0.05;
111	  const padY = bbH * 0.05;
112	  const pMinX = bbMinX - padX;
113	  const pW = bbW + 2 * padX;
114	  const pH = bbH + 2 * padY;
115	
116	  if (pW <= 0 || pH <= 0) return null;
117	
118	  // Uniform scale preserving aspect ratio
119	  const scaleX = widthMm / pW;
120	  const scaleY = heightMm / pH;
121	  const scale = Math.min(scaleX, scaleY);
122	
123	  // Center offset
124	  const renderedW = pW * scale;
125	  const renderedH = pH * scale;
126	  const offsetX = (widthMm - renderedW) / 2;
127	  const offsetY = (heightMm - renderedH) / 2;
128	
129	  // World → SVG: flip Y (architectural y-up → SVG y-down)
130	  const toSvg = (pt: XY): { sx: number; sy: number } => ({
131	    sx: (pt.xMm - pMinX) * scale + offsetX,
132	    sy: (bbMaxY + padY - pt.yMm) * scale + offsetY,
133	  });
134	
135	  const polyPoints = (pts: XY[]): string =>
136	    pts
137	      .map((pt) => {
138	        const { sx, sy } = toSvg(pt);
139	        return `${sx},${sy}`;
140	      })
141	      .join(' ');
142	
143	  return (
144	    <g>
145	      {floors.map((f) => (
146	        <polygon
147	          key={f.id}
148	          points={polyPoints(f.boundaryMm)}
149	          fill="#f0f0f0"
150	          stroke="#aaa"
151	          strokeWidth={0.3}
152	        />
153	      ))}
154	      {rooms.map((r) => (
155	        <polygon
156	          key={r.id}
157	          points={polyPoints(r.outlineMm)}
158	          fill="rgba(200,220,240,0.3)"
159	          stroke="none"
160	        />
161	      ))}
162	      {walls.map((w) => {
163	        const s = toSvg(w.start);
164	        const e = toSvg(w.end);
165	        const sw = Math.min(4, Math.max(0.5, w.thicknessMm * scale));
166	        return (
167	          <line
168	            key={w.id}
169	            x1={s.sx}
170	            y1={s.sy}
171	            x2={e.sx}
172	            y2={e.sy}
173	            stroke="#334155"
174	            strokeWidth={sw}
175	          />
176	        );
177	      })}
178	    </g>
179	  );
180	}
