182	function clientToSvgMm(
183	  svg: SVGSVGElement,
184	  clientX: number,
185	  clientY: number,
186	): { x: number; y: number } {
187	  const pt = svg.createSVGPoint();
188	  pt.x = clientX;
189	  pt.y = clientY;
190	  const ctm = svg.getScreenCTM();
191	  if (!ctm) {
192	    return { x: 0, y: 0 };
193	  }
194	  const sp = pt.matrixTransform(ctm.inverse());
195	  return { x: sp.x, y: sp.y };
196	}
