const savedViewSections = useMemo(() => {
  const all = Object.values(elementsById);
  const nonPerspective = all.filter(
    (e): e is Extract<Element, { kind: 'saved_view' }> =>
      e.kind === 'saved_view' && e.viewType !== 'perspective',
  );
  const perspective = all.filter(
    (e): e is Extract<Element, { kind: 'saved_view' }> =>
      e.kind === 'saved_view' && e.viewType === 'perspective',
  );
  const sections = [];
  if (nonPerspective.length > 0) {
    sections.push({
      id: 'saved-views',
      label: 'Saved Views',
      rows: nonPerspective
        .sort((a, b) => a.name.localeCompare(b.name))
        .map((v) => ({
          id: v.id,
          label: v.name,
          hint: 'saved 3D snapshot',
          renamable: true,
        })),
